sql:
SELECT COUNT(log_id) AS log_count
FROM version_logs
WHERE version_id = '1';

external_knowledge:
- 'Complex, mature projects' refers to projects with an average module count greater than 100;
- 'Fully addressed' means the project status is 'completed';
- 'Bumpy road with numerous bug fixes' implies more than 5 bugs were fixed in the version;
- 'Reached stable ground' signifies the version's release date.

sql:
SELECT DISTINCT d.developer_name
FROM projects p
INNER JOIN developers d ON p.lead_developer_id = d.developer_id;
